SELECT COUNT(DISTINCT rs.shared_with_group_id) 
FROM report_shares rs
INNER JOIN user_groups ug ON rs.shared_with_group_id = ug.group_id;

SELECT DISTINCT t.tool_name
FROM tools t
INNER JOIN analyses a ON t.tool_id = a.tool_id;

SELECT metadata_type, metadata_value
FROM metadata
WHERE sample_id = (SELECT sample_id FROM samples WHERE sample_name = 'Sample1');
